import os
from google.cloud import storage
from sklearn.externals import joblib

# Set environment variables
BUCKET_NAME = os.environ.get('ML_BUCKET_NAME')
MODEL_PATH_ENV = os.environ.get('MODEL_PATH')

# Initialize GCS client
client = storage.Client()

def get_latest_model_version():
    bucket = client.bucket(BUCKET_NAME)
    blobs = list(bucket.list_blobs(prefix=MODEL_PATH_ENV))
    if not blobs:
        raise ValueError("No models found in GCS")
    
    latest_blob = max(blobs, key=lambda x: x.name.split('/')[-1])
    return latest_blob.name.split('/')[-1]

def load_model(model_path):
    blob = client.bucket(BUCKET_NAME).blob(model_path)
    model_bytes = blob.download_as_string()
    return joblib.load(model_bytes)

# Get latest model version
latest_model_version = get_latest_model_version()

if MODEL_PATH_ENV:
    model_path = os.path.join(MODEL_PATH_ENV, latest_model_version)
else:
    raise ValueError("MODEL_PATH environment variable not set")

model = load_model(model_path)